// Determinar day_slot basado en día de semana
const day = new Date().getDay(); // 0=Dom, 1=Lun, 3=Mie, 5=Vie
const slotMap = { 1: 'MON', 3: 'WED', 5: 'FRI' };
const daySlot = slotMap[day] || 'MON'; // fallback MON para testing
return [{ json: { day_slot: daySlot, run_date: new Date().toISOString() } }];

