// Parsear respuesta de Claude y combinar con datos del prospecto
const batchItems = $('Loop (5 por batch)').all();
const aiItems = $input.all();
const out = [];
for (let i = 0; i < aiItems.length; i++) {
  const prospect = batchItems[i].json;
  let email = { subject: 'Consultoría IT para ' + prospect.company, body: 'Estimado ' + prospect.first_name + ',\n\nMe comunico de parte de ITCPR.' };
  try {
    const txt = aiItems[i].json.content[0].text.replace(/```json|```/g, '').trim();
    email = JSON.parse(txt);
  } catch (e) { /* usar fallback */ }
  out.push({
    json: {
      prospect_id: prospect.prospect_id,
      email: prospect.email,
      first_name: prospect.first_name,
      company: prospect.company,
      topic_id: prospect.topic_id,
      angle: prospect.angle,
      subject: email.subject,
      body: email.body
    }
  });
}
return out;
